import httpStatus3 from "http-status";

// src/utils/jwt.ts
import jwt from "jsonwebtoken";
var createToken = (payload, secret, expiresIn) => {
  const token = jwt.sign(payload, secret, expiresIn);
  return token;
};
var verifyToken = (token, secret) => {
  try {
    const verifiedToken = jwt.verify(token, secret);
    return {
      success: true,
      data: verifiedToken
    };
  } catch (error) {
    console.log("Token verifiy faild:", error);
    return {
      success: false,
      error: error.message
    };
  }
};
var jwtUtils = {
  createToken,
  verifyToken
};

// src/middlewares/auth.ts
var auth = (...requiredRole) => {
  return catchAsync(async (req, res, next) => {
    const token = req.cookies.accessToken ? req.cookies.accessToken : req.headers.authorization?.startsWith("Bearer") ? req.headers.authorization?.split(" ")[1] : req.headers.authorization;
    if (!token) {
      return res.status(httpStatus3.UNAUTHORIZED).json({
        success: false,
        statusCode: httpStatus3.UNAUTHORIZED,
        message: "User is not authorized to access this route"
      });
    }
    const verifiedToken = jwtUtils.verifyToken(token, config2.jwt_secret_key);
    if (!verifiedToken.success) {
      throw new Error(verifiedToken.error);
    }
    const { name, email, userId, role } = verifiedToken.data;
    if (requiredRole.length && !requiredRole.includes(role)) {
      throw new Error("User is not authorized to access this route");
    }
    const user = await prisma.user.findUnique({
      where: {
        id: userId,
        name,
        email,
        role
      }
    });
    if (!user) {
      throw new Error("User not found");
    }
    if (user.status === "BANNED") {
      throw new Error("User is inactive");
    }
    req.user = { name, email, userId, role };
    next();
  });
};
var auth_default = auth;

