import bcrypt2 from "bcrypt";
var loginUser = async (payload) => {
  const { email, password } = payload;
  const emailLowerCase = email.toLowerCase();
  const user = await prisma.user.findUnique({
    where: { email: emailLowerCase },
    include: {
      profile: true
    }
  });
  if (!user) {
    throw new Error("User not found");
  }
  const isPasswordMatched = await bcrypt2.compare(password, user.password);
  if (!isPasswordMatched) {
    throw new Error("Password is incorrect");
  }
  const jwtPayload = {
    name: user.name,
    userId: user.id,
    email: user.email,
    role: user.role
  };
  const accessToken = jwtUtils.createToken(jwtPayload, config2.jwt_secret_key, {
    expiresIn: config2.jwt_expires_in
  });
  const refreshToken = jwtUtils.createToken(
    jwtPayload,
    config2.jwt_refresh_secret_key,
    {
      expiresIn: config2.jwt_refresh_expires_in
    }
  );
  return {
    user: {
      name: user.name,
      email: user.email,
      userId: user.id,
      role: user.role
    },
    accessToken,
    refreshToken
  };
};
var authService = {
  loginUser
};

