var createProperty = async (payload, userId) => {
  const result = await prisma.property.create({
    data: {
      ...payload,
      authorId: userId
    }
  });
  return result;
};
var getAllProperties = async (query) => {
  const { location, category, minPrice, maxPrice } = query;
  const where = {};
  if (location) {
    where.location = {
      contains: location,
      mode: "insensitive"
    };
  }
  if (category) {
    where.category = category;
  }
  if (minPrice || maxPrice) {
    where.price = {};
    if (minPrice) {
      where.price.gte = Number(minPrice);
    }
    if (maxPrice) {
      where.price.lte = Number(maxPrice);
    }
  }
  const result = await prisma.property.findMany({
    where,
    include: {
      author: {
        select: {
          id: true,
          name: true,
          email: true,
          role: true
        }
      },
      // rentalRequests: {
      //   include: {
      //     tenant: {
      //       select: {
      //         name: true,
      //         email: true,
      //         role: true,
      //       },
      //     },
      //   },
      // },
      reviews: true
    },
    orderBy: {
      createdAt: "desc"
    }
  });
  if (result.length === 0) {
    throw new Error("No data available");
  }
  return result;
};
var getPropertyById = async (propertyId) => {
  const transactionResult = await prisma.$transaction(async (tx) => {
    const property = await tx.property.findUnique({
      where: {
        id: propertyId
      }
    });
    if (!property) {
      throw new Error("Property not found");
    }
    await tx.property.update({
      where: {
        id: propertyId
      },
      data: {
        views: {
          increment: 1
        }
      }
    });
    return await tx.property.findUnique({
      where: {
        id: propertyId
      },
      include: {
        author: {
          select: {
            id: true,
            name: true,
            email: true,
            role: true
          }
        },
        reviews: true
      }
    });
  });
  return transactionResult;
};
var getAllPropertyCategories = async () => {
  const result = await prisma.property.findMany({
    select: {
      category: true
    },
    distinct: ["category"]
  });
  if (result.length === 0) {
    throw new Error(
      "Property categories not found"
    );
  }
  return result.map((item) => item.category);
};
var getAdminProperties = async () => {
  const result = await prisma.property.findMany({
    include: {
      author: {
        select: {
          id: true,
          name: true,
          email: true
        }
      },
      reviews: true
    },
    orderBy: {
      createdAt: "desc"
    }
  });
  return result;
};
var updateProperty = async (propertyId, payload, authorId) => {
  const property = await prisma.property.findUnique({
    where: {
      id: propertyId
    }
  });
  if (!property) {
    throw new Error("Property not found");
  }
  if (property.authorId !== authorId) {
    throw new Error("You are not authorized to update this property");
  }
  const updateData = {
    ...payload,
    ...payload.category && {
      category: payload.category.toUpperCase()
    },
    ...payload.status && {
      status: payload.status.toUpperCase()
    }
  };
  return await prisma.property.update({
    include: {
      author: {
        select: {
          id: true,
          name: true,
          email: true
        }
      },
      reviews: true
    },
    where: {
      id: propertyId
    },
    data: updateData
  });
};
var updateRentalRequestStatus = async (rentalRequestId, userId, userRole, status) => {
  const rentalRequest = await prisma.rentalRequest.findUnique({
    where: {
      id: rentalRequestId
    },
    include: {
      property: true
    }
  });
  if (!rentalRequest) {
    throw new Error("Rental request not found");
  }
  const isLandlordOwner = userRole === Role.LANDLORD && rentalRequest.property.authorId === userId;
  const isAdmin = userRole === Role.ADMIN;
  if (!isLandlordOwner && !isAdmin) {
    throw new Error(
      "You are not authorized to update this rental request"
    );
  }
  if (rentalRequest.rentalstatus !== RentalRequestStatus.PENDING) {
    throw new Error("This rental request has already been processed");
  }
  return await prisma.$transaction(async (tx) => {
    const updatedRequest = await tx.rentalRequest.update({
      where: {
        id: rentalRequestId
      },
      data: {
        rentalstatus: status
      },
      include: {
        property: true,
        tenant: {
          select: {
            id: true,
            name: true,
            email: true,
            role: true
          }
        }
      }
    });
    if (status === RentalRequestStatus.APPROVED) {
      await tx.property.update({
        where: {
          id: rentalRequest.propertyId
        },
        data: {
          status: PropertyStatus.UNAVAILABLE
        }
      });
      await tx.rentalRequest.updateMany({
        where: {
          propertyId: rentalRequest.propertyId,
          id: {
            not: rentalRequestId
          },
          rentalstatus: RentalRequestStatus.PENDING
        },
        data: {
          rentalstatus: RentalRequestStatus.REJECTED
        }
      });
      await tx.payment.create({
        data: {
          userId: rentalRequest.tenantId,
          rentalRequestId,
          amount: rentalRequest.property.price,
          status: PaymentStatus.UNPAID,
          meta: {}
        }
      });
    }
    return updatedRequest;
  });
};
var getLandlordRentalRequests = async (landlordId) => {
  return await prisma.rentalRequest.findMany({
    where: {
      property: {
        authorId: landlordId
      }
    },
    include: {
      payment: {
        select: {
          id: true,
          amount: true,
          status: true,
          transactionId: true
        }
      },
      property: true,
      tenant: {
        select: {
          id: true,
          name: true,
          email: true,
          role: true,
          reviews: true
        }
      }
    }
  });
};
var deleteProperty = async (propertyId, authorId, userRole) => {
  const property = await prisma.property.findUnique({
    where: {
      id: propertyId
    }
  });
  if (!property) {
    throw new Error("Property not found");
  }
  if (userRole !== Role.ADMIN && property.authorId !== authorId) {
    throw new Error("You are not authorized to delete this property");
  }
  return await prisma.property.delete({
    where: {
      id: propertyId
    }
  });
};
var propertyService = {
  createProperty,
  getAllProperties,
  getAllPropertyCategories,
  getAdminProperties,
  getPropertyById,
  updateProperty,
  updateRentalRequestStatus,
  getLandlordRentalRequests,
  deleteProperty
};

