var getRentalRequestDetails = async (requestId, userId, userRole) => {
  const request = await prisma.rentalRequest.findUnique({
    where: {
      id: requestId
    },
    include: {
      tenant: {
        select: {
          id: true,
          name: true,
          email: true,
          role: true
        }
      },
      payment: true,
      property: {
        include: {
          author: {
            select: {
              id: true,
              name: true,
              email: true,
              role: true
            }
          }
        }
      }
    }
  });
  if (!request) {
    throw new Error("Rental request not found");
  }
  if (userRole === Role.ADMIN) {
    return request;
  }
  if (userRole === Role.TENANT && request.tenantId === userId) {
    return request;
  }
  if (userRole === Role.LANDLORD && request.property.authorId === userId) {
    return request;
  }
  throw new Error("You are not authorized to view this rental request");
};
